document.addEventListener('DOMContentLoaded', initializeApp);

function returnToAppSelector() {
    if (window.parent && window.parent !== window) {
        window.parent.postMessage({ type: 'sats:show-app-selector' }, '*');
        return;
    }
    window.location.href = 'index.html?appSelector=1';
}

async function initializeApp() {
    applySidebarState();
    loadWorkbookSnapshot();
    buildRiskIndex();
    applyViewSettings();
    renderTabs();
    renderFilters();
    renderTable();
    updateCounts();
    setupKeyboardShortcuts();
    await loadSavedChanges();
}

function applySidebarState() {
    const collapsed = getStoredSidebarState();
    document.body.classList.toggle('sidebar-collapsed', collapsed);
    updateSidebarToggle();
}

function toggleSidebar() {
    const collapsed = !document.body.classList.contains('sidebar-collapsed');
    document.body.classList.toggle('sidebar-collapsed', collapsed);
    storeSidebarState(collapsed);
    updateSidebarToggle();
}

function getStoredSidebarState() {
    try {
        return localStorage.getItem('procedimentos_sidebar_collapsed') === '1';
    } catch (error) {
        return false;
    }
}

function storeSidebarState(collapsed) {
    try {
        localStorage.setItem('procedimentos_sidebar_collapsed', collapsed ? '1' : '0');
    } catch (error) {
        // Storage can be unavailable in restricted browser modes; the toggle still works for the current page.
    }
}

function updateSidebarToggle() {
    const toggle = document.getElementById('sidebarToggle');
    if (!toggle) return;

    const collapsed = document.body.classList.contains('sidebar-collapsed');
    toggle.innerHTML = collapsed ? SIDEBAR_OPEN_ICON : SIDEBAR_CLOSE_ICON;
    toggle.title = collapsed ? 'Abrir menu lateral' : 'Fechar menu lateral';
    toggle.setAttribute('aria-label', toggle.title);
    toggle.setAttribute('aria-expanded', String(!collapsed));
}

function setupKeyboardShortcuts() {
    document.addEventListener('keydown', (e) => {
        if (e.ctrlKey && e.key === 'f') {
            e.preventDefault();
            document.getElementById('searchInput').focus();
        }
        if (e.ctrlKey && e.key === 's' && isAdmin) {
            e.preventDefault();
            saveChanges();
        }
        if (e.key === 'Escape') {
            closeLogin();
        }
    });
}

// ============================================
// SUPABASE PERSISTENCE
// ============================================
function isSupabaseConfigured() {
    return Boolean(SUPABASE_CONFIG.url && SUPABASE_CONFIG.anonKey && SUPABASE_CONFIG.table);
}

async function supabaseRequest(path, options = {}) {
    const response = await fetch(`${SUPABASE_CONFIG.url}/rest/v1/${path}`, {
        ...options,
        headers: {
            apikey: SUPABASE_CONFIG.anonKey,
            Authorization: `Bearer ${SUPABASE_CONFIG.anonKey}`,
            'Content-Type': 'application/json',
            ...(options.headers || {})
        }
    });

    if (!response.ok) {
        const detail = await response.text();
        throw new Error(`Supabase ${response.status}: ${detail || response.statusText}`);
    }

    if (response.status === 204) return null;

    const text = await response.text();
    return text ? JSON.parse(text) : null;
}

async function loadSavedChanges() {
    if (!isSupabaseConfigured()) return;

    try {
        const rows = await supabaseRequest(`${SUPABASE_CONFIG.table}?select=sheet_name,row_index,col_index,value&order=updated_at.asc`, {
            method: 'GET'
        });

        if (!Array.isArray(rows) || rows.length === 0) {
            savedChangesLoaded = true;
            return;
        }

        rows.forEach(applySavedCellEdit);
        savedChangesLoaded = true;
        buildRiskIndex();
        renderTabs();
        renderFilters();
        renderTable();
        updateCounts();
        showToast(`${rows.length} alteração(ões) salva(s) carregada(s).`, 'success');
    } catch (error) {
        console.error('Failed to load saved changes:', error);
        showToast('Não foi possível carregar alterações salvas do Supabase.', 'error');
    }
}

function applySavedCellEdit(edit) {
    const sheet = SHEET_DATA[edit.sheet_name];
    const rowIndex = Number(edit.row_index);
    const colIndex = Number(edit.col_index);

    if (!sheet || !Number.isInteger(rowIndex) || !Number.isInteger(colIndex) || rowIndex < 0 || colIndex < 0) return;
    if (!sheet[rowIndex]) sheet[rowIndex] = [];

    while (sheet[rowIndex].length <= colIndex) {
        sheet[rowIndex].push('');
    }

    sheet[rowIndex][colIndex] = edit.value || '';
}

async function persistCellChanges(changedCells) {
    if (!isSupabaseConfigured() || changedCells.length === 0) return false;

    const payload = changedCells.map(cell => ({
        sheet_name: cell.sheetName,
        row_index: cell.rowIndex,
        col_index: cell.colIndex,
        value: cell.value,
        updated_by: getAdminUserLabel()
    }));

    await supabaseRequest(`${SUPABASE_CONFIG.table}?on_conflict=sheet_name,row_index,col_index`, {
        method: 'POST',
        headers: {
            Prefer: 'resolution=merge-duplicates,return=minimal'
        },
        body: JSON.stringify(payload)
    });

    return true;
}

function getAdminUserLabel() {
    return document.getElementById('adminUser')?.value?.trim() || 'admin';
}

function loadWorkbookSnapshot() {
    try {
        const raw = localStorage.getItem(WORKBOOK_STORAGE_KEY);
        if (!raw) return;

        const snapshot = JSON.parse(raw);
        if (!snapshot || !snapshot.sheetData) return;

        Object.keys(snapshot.sheetData).forEach(sheetName => {
            if (!SHEET_DATA[sheetName]) return;
            SHEET_DATA[sheetName] = snapshot.sheetData[sheetName];
            CELL_STYLES[sheetName] = snapshot.cellStyles?.[sheetName] || [];
        });
    } catch (error) {
        console.warn('Failed to load local workbook snapshot:', error);
    }
}

function persistWorkbookSnapshot() {
    try {
        localStorage.setItem(WORKBOOK_STORAGE_KEY, JSON.stringify({
            sheetData: SHEET_DATA,
            cellStyles: CELL_STYLES
        }));
    } catch (error) {
        console.warn('Failed to persist local workbook snapshot:', error);
    }
}

function getCellStyle(sheetName, rowIndex, colIndex) {
    if (colIndex < 0) return null;
    return CELL_STYLES?.[sheetName]?.[rowIndex]?.[colIndex] || null;
}

function getInlineStyle(style, options = {}) {
    if (!style) return '';

    const rules = [];
    if (style.color) rules.push(`color: ${style.color}`);
    if (options.includeBackground && style.bg) rules.push(`background: ${style.bg}`);
    if (style.bold) rules.push('font-weight: 700');
    if (style.italic) rules.push('font-style: italic');
    if (style.underline) rules.push('text-decoration: underline');

    return rules.join('; ');
}

function applyCellStyle(element, style, options = {}) {
    if (!element || !style) return;

    if (style.color) element.style.color = style.color;
    if (style.bold) element.style.fontWeight = '700';
    if (style.italic) element.style.fontStyle = 'italic';
    if (style.underline) element.style.textDecoration = 'underline';
    if (options.includeBackground && style.bg) element.style.background = style.bg;
    if (options.includeBorder && style.bg) element.style.borderColor = style.bg;
}

function formatStyledCellContent(value, rowIndex, colIndex, options = {}) {
    const text = (value || '').toString();
    const emptyHtml = options.emptyHtml || '<span class="risk-empty">--</span>';
    if (!text.trim()) return emptyHtml;

    const style = getCellStyle(currentSheet, rowIndex, colIndex);
    if (style?.rich?.length) {
        return style.rich.map(run => {
            const runStyle = getInlineStyle(run);
            const styleAttr = runStyle ? ` style="${runStyle}"` : '';
            return `<span${styleAttr}>${highlightText(escapeHtml(run.text || ''))}</span>`;
        }).join('');
    }

    const inlineStyle = getInlineStyle(style);
    const styleAttr = inlineStyle ? ` style="${inlineStyle}"` : '';
    return `<span${styleAttr}>${highlightText(escapeHtml(text))}</span>`;
}

function getRiskStyleForType(type) {
    return RISK_STYLE_COLORS[type] || null;
}

function getRiskGroupNameForType(type) {
    return getRiskStyleForType(type)?.group || getRiskTypeLabel(type) || '';
}

// ============================================
// TABS
// ============================================
function renderTabs() {
    const tabsContainer = document.getElementById('tabs');
    tabsContainer.innerHTML = '';

    SHEET_NAMES.forEach(name => {
        const btn = document.createElement('button');
        btn.className = 'tab' + (name === currentSheet ? ' active' : '');
        const displayName = name.length > 25 ? name.substring(0, 22) + '...' : name;
        const riskDetailConfig = getRiskDetailConfig((SHEET_DATA[name] && SHEET_DATA[name][0]) || [], name);
        const recordCount = isLaudoSheet(name)
            ? buildLaudoRecords(SHEET_DATA[name], name).length
            : riskDetailConfig
                ? countRiskDetailRows(SHEET_DATA[name], riskDetailConfig)
                : SHEET_DATA[name].length - 1;
        btn.innerHTML = `${displayName} <span class="tab-badge">${recordCount}</span>`;
        btn.title = name;
        btn.onclick = () => switchSheet(name);
        tabsContainer.appendChild(btn);
    });
}

function switchSheet(name) {
    currentSheet = name;
    renderTabs();
    resetFilterValues();
    renderFilters();
    renderTable();
    updateCounts();
}

// ============================================
// FILTERS AND RISK CLASSIFICATION
// ============================================
function renderFilters() {
    renderRiskTypeOptions();
    renderFieldOptions();
    renderRiskLegend();
    updateFilterControls();
}

function renderRiskTypeOptions() {
    const select = document.getElementById('riskTypeFilter');
    select.innerHTML = '<option value="">Todos os tipos</option>';

    RISK_TYPES.forEach(type => {
        const option = document.createElement('option');
        option.value = type.key;
        option.textContent = type.label;
        select.appendChild(option);
    });

    select.value = riskTypeFilter;
}

function renderFieldOptions() {
    const select = document.getElementById('fieldFilter');
    const headers = (SHEET_DATA[currentSheet] && SHEET_DATA[currentSheet][0]) || [];
    select.innerHTML = '<option value="all">Todos os campos</option>';

    headers.forEach((header, index) => {
        const label = cleanCellText(header) || `Coluna ${index + 1}`;
        const option = document.createElement('option');
        option.value = index.toString();
        option.textContent = label;
        select.appendChild(option);
    });

    select.value = fieldFilter;
}

function renderRiskLegend() {
    const legend = document.getElementById('riskLegend');
    legend.innerHTML = '';

    RISK_TYPES.forEach(type => {
        const chip = document.createElement('span');
        chip.className = `risk-chip risk-${type.key}`;
        chip.textContent = type.label;
        legend.appendChild(chip);
    });
}

function handleFilters() {
    riskTypeFilter = document.getElementById('riskTypeFilter').value;
    riskNameTerm = document.getElementById('riskNameInput').value.trim();
    fieldFilter = document.getElementById('fieldFilter').value || 'all';
    searchTerm = document.getElementById('searchInput').value.trim();
    updateFilterControls();
    renderTable();
}

function resetFilterValues() {
    riskTypeFilter = '';
    riskNameTerm = '';
    fieldFilter = 'all';
    searchTerm = '';

    const riskType = document.getElementById('riskTypeFilter');
    const riskName = document.getElementById('riskNameInput');
    const field = document.getElementById('fieldFilter');
    const search = document.getElementById('searchInput');

    if (riskType) riskType.value = '';
    if (riskName) riskName.value = '';
    if (field) field.value = 'all';
    if (search) search.value = '';
    updateFilterControls();
}

function clearAllFilters() {
    resetFilterValues();
    renderTable();
}

function clearRiskNameSearch() {
    document.getElementById('riskNameInput').value = '';
    riskNameTerm = '';
    updateFilterControls();
    renderTable();
}

function updateFilterControls() {
    const clearSearch = document.getElementById('clearSearch');
    const clearRiskName = document.getElementById('clearRiskName');
    const clearFilters = document.getElementById('clearFilters');

    if (clearSearch) clearSearch.classList.toggle('visible', searchTerm.length > 0);
    if (clearRiskName) clearRiskName.classList.toggle('visible', riskNameTerm.length > 0);
    if (clearFilters) clearFilters.disabled = !hasActiveFilters();
}

function hasActiveFilters() {
    return Boolean(searchTerm || riskNameTerm || riskTypeFilter || fieldFilter !== 'all');
}

function hasFilteringCriteria() {
    return Boolean(searchTerm || riskNameTerm || riskTypeFilter);
}

function buildRiskIndex() {
    riskNameToType = new Map();
    rowRiskTypes = {};

    buildRascunhoRiskIndex();

    SHEET_NAMES.forEach(sheetName => {
        if (sheetName === 'Rascunho') return;

        const data = SHEET_DATA[sheetName] || [];
        const riskConfig = getRiskDetailConfig(data[0] || [], sheetName);
        const sheetRiskType = getSheetRiskType(sheetName);
        let currentPgrType = '';
        rowRiskTypes[sheetName] = {};

        for (let i = riskConfig?.startIndex ?? 1; i < data.length; i++) {
            const row = data[i] || [];
            if (!rowHasContent(row)) continue;

            const riskName = getRiskName(row, sheetName);
            const styleType = getRiskTypeFromCellStyle(sheetName, i, riskConfig?.riskIndex ?? 0);
            let type = styleType || sheetRiskType || getRiskTypeFromText(row[0]) || getRiskTypeByRiskName(riskName);

            if (sheetName === 'PGR Riscos') {
                const boundaryType = getPgrBoundaryType(riskName);
                if (boundaryType) currentPgrType = boundaryType;
                if (!type && currentPgrType) type = currentPgrType;
                if (type) currentPgrType = type;
            }

            if (type) rowRiskTypes[sheetName][i] = type;
        }
    });
}

function buildRascunhoRiskIndex() {
    const data = SHEET_DATA['Rascunho'] || [];
    let currentType = '';
    rowRiskTypes['Rascunho'] = {};

    for (let i = 1; i < data.length; i++) {
        const row = data[i] || [];
        const categoryType = getRiskTypeFromText(row[0]);
        if (categoryType) currentType = categoryType;

        const riskName = cleanCellText(row[1] || '');
        if (currentType && riskName) {
            riskNameToType.set(normalizeRiskName(riskName), currentType);
        }

        if (currentType && rowHasContent(row)) {
            rowRiskTypes['Rascunho'][i] = currentType;
        }
    }
}

function getSheetRiskType(sheetName) {
    const normalized = normalizeText(sheetName);
    return RISK_TYPES.find(type => type.aliases.some(alias => normalized.includes(normalizeText(alias))))?.key || '';
}

function getRiskTypeFromText(value) {
    const normalized = normalizeText(value);
    if (!normalized) return '';

    const match = RISK_TYPES.find(type => type.aliases.some(alias => normalized === normalizeText(alias)));
    return match ? match.key : '';
}

function getRiskTypeByRiskName(value) {
    const normalized = normalizeRiskName(value);
    if (!normalized) return '';
    if (riskNameToType.has(normalized)) return riskNameToType.get(normalized);

    for (const [riskName, type] of riskNameToType.entries()) {
        if (riskName.length < 6 || normalized.length < 6) continue;
        if (riskName.includes(normalized) || normalized.includes(riskName)) return type;
    }

    return '';
}

function getRiskTypeFromCellStyle(sheetName, rowIndex, colIndex) {
    const fill = getCellStyle(sheetName, rowIndex, colIndex)?.bg;
    if (!fill) return '';

    const normalizedFill = fill.toUpperCase();
    const match = RISK_FILL_TO_TYPE.find(item => item.colors.includes(normalizedFill));
    return match?.key || '';
}

function getPgrBoundaryType(value) {
    const normalized = normalizeRiskName(value);

    if (normalized.includes('1,2,4-trimetilbenzeno')) return 'quimico';
    if (normalized.includes('agentes biologicos infecciosos')) return 'biologico';
    if (normalized.includes('exposicao a superficies')) return 'acidente';
    if (normalized.includes('condicoes ambientais de trabalho')) return 'ergonomico';

    return '';
}

function getRiskTypeForRow(sheetName, row, rowIndex) {
    const config = getRiskDetailConfig((SHEET_DATA[sheetName] && SHEET_DATA[sheetName][0]) || [], sheetName);
    return (rowRiskTypes[sheetName] && rowRiskTypes[sheetName][rowIndex])
        || getRiskTypeFromCellStyle(sheetName, rowIndex, config?.riskIndex ?? 0)
        || getSheetRiskType(sheetName)
        || getRiskTypeFromText(row[0])
        || getRiskTypeByRiskName(getRiskName(row, sheetName));
}

function getRiskName(row, sheetName) {
    const config = getRiskDetailConfig((SHEET_DATA[sheetName] && SHEET_DATA[sheetName][0]) || [], sheetName);
    if (config && config.riskIndex >= 0) return cleanCellText(row[config.riskIndex] || row[0] || '');
    return cleanCellText(row[0] || '');
}

function rowMatchesFilters(row, rowIndex) {
    if (!rowHasContent(row) && hasFilteringCriteria()) return false;

    const riskType = getRiskTypeForRow(currentSheet, row, rowIndex);
    if (riskTypeFilter && riskType !== riskTypeFilter) return false;

    if (riskNameTerm) {
        const riskName = normalizeText(getRiskName(row, currentSheet));
        if (!riskName.includes(normalizeText(riskNameTerm))) return false;
    }

    if (searchTerm) {
        const term = normalizeText(searchTerm);
        const cells = fieldFilter === 'all' ? row : [row[Number(fieldFilter)] || ''];
        if (!cells.some(cell => normalizeText(cell).includes(term))) return false;
    }

    return true;
}

function rowHasContent(row) {
    return row.some(cell => cleanCellText(cell).length > 0);
}

function cleanCellText(value) {
    return (value || '').toString().replace(/\t/g, ' ').replace(/\s+/g, ' ').trim();
}

function normalizeRiskName(value) {
    return normalizeText(value).replace(/\s*-\s*\d[\d.]*$/g, '').trim();
}

function normalizeText(value) {
    return (value || '')
        .toString()
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '')
        .toLowerCase()
        .replace(/\s+/g, ' ')
        .trim();
}

function isLaudoSheet(sheetName) {
    return normalizeText(sheetName).startsWith('laudos-');
}

function getLaudoKind(sheetName) {
    const normalized = normalizeText(sheetName);
    if (normalized.includes('fisic')) return 'fisico';
    if (normalized.includes('biologic')) return 'biologico';
    if (normalized.includes('quimic')) return 'quimico';
    return '';
}

function getLaudoTypeLabel(sheetName) {
    const kind = getLaudoKind(sheetName);
    if (kind === 'fisico') return 'Laudo Físico';
    if (kind === 'biologico') return 'Laudo Biológico';
    if (kind === 'quimico') return 'Laudo Químico';
    return 'Laudo técnico';
}

// ============================================
// VIEW CONTROLS
// ============================================
function applyViewSettings() {
    document.body.dataset.viewDensity = DENSITY_LEVELS[densityIndex].key;
    document.body.dataset.columnView = columnViewMode;
    updateViewControls();
}

function changeDensity(delta) {
    densityIndex = Math.max(0, Math.min(DENSITY_LEVELS.length - 1, densityIndex + delta));
    applyViewSettings();
}

function setColumnView(mode) {
    columnViewMode = mode;
    applyViewSettings();
    renderTable();
}

function resetColumnWidths() {
    columnViewMode = 'fit';
    applyViewSettings();
    renderTable();
    showToast('Colunas ajustadas à tela.', 'info');
}

function updateViewControls() {
    const density = DENSITY_LEVELS[densityIndex];
    const label = document.getElementById('densityLabel');
    const down = document.getElementById('densityDown');
    const up = document.getElementById('densityUp');
    const fit = document.getElementById('fitColumns');
    const wide = document.getElementById('wideColumns');

    if (label) label.textContent = density.label;
    if (down) down.disabled = densityIndex === 0;
    if (up) up.disabled = densityIndex === DENSITY_LEVELS.length - 1;
    if (fit) fit.classList.toggle('active', columnViewMode === 'fit');
    if (wide) wide.classList.toggle('active', columnViewMode === 'wide');
}

// ============================================
// TABLE RENDERING
// ============================================
function getColumnWidths(headers, numCols) {
    if (columnViewMode === 'wide') {
        return Array.from({ length: numCols }, (_, c) => `${getDefaultColumnWidthPx(headers[c], c)}px`);
    }

    const weights = Array.from({ length: numCols }, (_, c) => getDefaultColumnWeight(headers[c], c));
    const total = weights.reduce((sum, weight) => sum + weight, 0) || 1;
    return weights.map(weight => `${((weight / total) * 100).toFixed(3)}%`);
}

function getDefaultColumnWeight(header, index) {
    const headerName = normalizeText(header);

    if (currentSheet === 'Planejamento') {
        if (index === 0) return 0.55;
        if (index === 1) return 1.55;
        return 1.1;
    }

    if (currentSheet === 'Rascunho') {
        if (index === 0) return 0.8;
        if (index === 1) return 1.55;
        return 1.1;
    }

    if (headerName.includes('risco')) return 1.05;
    if (headerName.includes('descricao')) return 1.55;
    if (headerName.includes('fundamentacao')) return 1.35;
    if (headerName.includes('possiveis')) return 1.35;
    if (headerName.includes('perfil')) return 1.15;
    if (headerName.includes('matriz')) return 1.0;
    if (headerName.includes('acoes')) return 1.65;

    return index === 0 ? 0.9 : 1.15;
}

function getDefaultColumnWidthPx(header, index) {
    const headerName = normalizeText(header);

    if (currentSheet === 'Planejamento') {
        if (index === 0) return 140;
        if (index === 1) return 460;
        return 340;
    }

    if (currentSheet === 'Rascunho') {
        if (index === 0) return 190;
        if (index === 1) return 430;
        return 390;
    }

    if (headerName.includes('risco')) return 260;
    if (headerName.includes('descricao')) return 420;
    if (headerName.includes('fundamentacao')) return 390;
    if (headerName.includes('possiveis')) return 390;
    if (headerName.includes('perfil')) return 340;
    if (headerName.includes('matriz')) return 300;
    if (headerName.includes('acoes')) return 460;

    return index === 0 ? 240 : 360;
}

function startColumnResize(event, table, colIndex) {
    if (event.button !== 0) return;

    const col = table.querySelector(`col[data-col="${colIndex}"]`);
    const th = table.querySelector(`thead th:nth-child(${colIndex + 1})`);
    if (!col || !th) return;

    const startX = event.clientX;
    const startWidth = th.getBoundingClientRect().width;

    columnViewMode = 'custom';
    applyViewSettings();
    document.body.classList.add('resizing-column');
    event.preventDefault();

    const handleMove = (moveEvent) => {
        const nextWidth = startWidth + moveEvent.clientX - startX;
        setColumnWidth(table, colIndex, nextWidth);
    };

    const stopResize = () => {
        document.body.classList.remove('resizing-column');
        document.removeEventListener('mousemove', handleMove);
        document.removeEventListener('mouseup', stopResize);
    };

    document.addEventListener('mousemove', handleMove);
    document.addEventListener('mouseup', stopResize);
}

function setColumnWidth(table, colIndex, width) {
    const nextWidth = Math.max(180, Math.min(980, Math.round(width)));
    const col = table.querySelector(`col[data-col="${colIndex}"]`);
    const th = table.querySelector(`thead th:nth-child(${colIndex + 1})`);

    if (col) col.style.width = `${nextWidth}px`;
    if (th) th.style.width = `${nextWidth}px`;
}

function getHeaderIndex(headers, aliases) {
    const normalizedAliases = aliases.map(alias => normalizeText(alias));
    return headers.findIndex(header => {
        const normalizedHeader = normalizeText(header);
        return normalizedAliases.some(alias => normalizedHeader.includes(alias));
    });
}

function getRiskDetailConfig(headers, sheetName = currentSheet) {
    let riskIndex;
    let groupIndex;
    const normalizedSheet = normalizeText(sheetName);
    const hasHeaderModel = !['laudos-biologicos', 'laudos-quimicos'].includes(normalizedSheet);
    const isLaudoSheet = normalizedSheet.startsWith('laudos-');

    if (normalizeText(headers[0]).includes('riscos mais utilizados')) {
        riskIndex = 1;
        groupIndex = 0;
    } else if (normalizedSheet === 'laudos-fisicos' && normalizeText(headers[1]).includes('analise')) {
        riskIndex = 0;
        groupIndex = -1;
    } else {
        riskIndex = getHeaderIndex(headers, ['risco', 'perigo fator de risco']);
        groupIndex = getHeaderIndex(headers, ['grupo']);
    }

    const config = {
        sheetName,
        riskIndex,
        groupIndex,
        startIndex: 1,
        groupRows: false,
        descriptionIndex: getHeaderIndex(headers, ['descricao']),
        legalIndex: getHeaderIndex(headers, ['fundamentacao legal', 'fundamentacao']),
        injuriesIndex: getHeaderIndex(headers, ['possiveis lesoes', 'agravos a saude']),
        profileIndex: getHeaderIndex(headers, ['perfil de exposicao', 'perfil']),
        matrixIndex: getHeaderIndex(headers, ['matriz de risco', 'matriz']),
        actionsIndex: getHeaderIndex(headers, ['acoes necessarias', 'acoes'])
    };

    const hasDetailFields = [
        config.descriptionIndex,
        config.legalIndex,
        config.injuriesIndex,
        config.profileIndex,
        config.actionsIndex
    ].some(index => index >= 0);

    if (config.riskIndex >= 0 && hasDetailFields) return config;

    if (hasHeaderModel && config.riskIndex >= 0) {
        return {
            sheetName,
            riskIndex: config.riskIndex,
            groupIndex: config.groupIndex,
            startIndex: 1,
            groupRows: isLaudoSheet,
            genericFields: buildGenericFieldConfig(headers, config.riskIndex, config.groupIndex)
        };
    }

    if (normalizedSheet.startsWith('laudos-')) {
        return {
            sheetName,
            riskIndex: 0,
            groupIndex: -1,
            startIndex: 0,
            groupRows: true,
            genericFields: buildGenericFieldConfig(headers, 0, -1, true)
        };
    }

    return null;
}

function buildGenericFieldConfig(headers, riskIndex, groupIndex, useColumnLabels = false) {
    return headers
        .map((header, index) => ({
            index,
            label: useColumnLabels ? `Coluna ${index + 1}` : (cleanCellText(header) || `Coluna ${index + 1}`)
        }))
        .filter(field => field.index !== riskIndex && field.index !== groupIndex);
}

function countRiskDetailRows(data, config) {
    if (config.groupRows) {
        return buildGroupedRiskRecords(data, config).length;
    }

    return data
        .slice(config.startIndex ?? 1)
        .filter(row => rowHasContent(row) && cleanCellText(row[config.riskIndex] || '').length > 0)
        .length;
}

function getRiskTypeLabel(type) {
    return RISK_TYPES.find(item => item.key === type)?.label || '';
}

function getRiskGroupLabel(rowData, config, riskType) {
    if (config.groupIndex >= 0) {
        const groupValue = cleanCellText(rowData[config.groupIndex] || '');
        if (groupValue) return groupValue;
    }

    return getRiskTypeLabel(riskType) || 'Não classificado';
}

function buildGroupedRiskRecords(data, config) {
    const records = [];
    let currentRecord = null;
    let pendingSection = '';
    const startIndex = config.startIndex ?? 1;

    for (let rowIndex = startIndex; rowIndex < data.length; rowIndex++) {
        const row = data[rowIndex] || [];
        if (!rowHasContent(row)) continue;

        if (isRepeatedHeaderRow(row, config)) {
            pendingSection = getRepeatedHeaderLabel(row, config) || pendingSection;
            continue;
        }

        const primaryText = cleanCellText(row[config.riskIndex] || '');
        const startsRecord = Boolean(primaryText) || !currentRecord;

        if (startsRecord) {
            const title = primaryText || getFirstNonEmptyCell(row)?.value || `Registro ${records.length + 1}`;
            currentRecord = {
                title,
                section: pendingSection,
                primaryIndex: rowIndex,
                primaryRow: row,
                rows: []
            };
            records.push(currentRecord);
            pendingSection = '';
        }

        currentRecord.rows.push({ row, rowIndex });
    }

    return records;
}

function isRepeatedHeaderRow(row, config) {
    const primary = normalizeText(row[config.riskIndex] || '');
    if (!primary) return false;

    if (['risco', 'riscos', 'perigo fator de risco'].includes(primary)) return true;

    const nonEmptyCells = row
        .map((value, index) => ({ value: cleanCellText(value || ''), index }))
        .filter(cell => cell.value);

    if (nonEmptyCells.length <= 2) {
        const normalizedValues = nonEmptyCells.map(cell => normalizeText(cell.value));
        return normalizedValues.some(value => ['risco', 'grupo'].includes(value))
            && normalizedValues.some(value => ['analise', 'insalubridade', 'aposentadoria especial'].includes(value));
    }

    return false;
}

function getRepeatedHeaderLabel(row, config) {
    return row
        .map((value, index) => ({ value: cleanCellText(value || ''), index }))
        .filter(cell => cell.value && cell.index !== config.riskIndex)
        .map(cell => cell.value)
        .find(value => normalizeText(value) !== 'risco') || '';
}

function getFirstNonEmptyCell(row) {
    for (let index = 0; index < row.length; index++) {
        const value = cleanCellText(row[index] || '');
        if (value) return { index, value };
    }
    return null;
}

function recordMatchesFilters(record, config) {
    const riskType = getRiskTypeForRow(currentSheet, record.primaryRow, record.primaryIndex);
    if (riskTypeFilter && riskType !== riskTypeFilter) return false;

    if (riskNameTerm) {
        const title = normalizeText(record.title);
        if (!title.includes(normalizeText(riskNameTerm))) return false;
    }

    if (searchTerm) {
        const term = normalizeText(searchTerm);
        const matchesSearch = record.rows.some(({ row }) => {
            const cells = fieldFilter === 'all' ? row : [row[Number(fieldFilter)] || ''];
            return cells.some(cell => normalizeText(cell).includes(term));
        });
        if (!matchesSearch) return false;
    }

    return true;
}

function buildLaudoRecords(data, sheetName) {
    return getLaudoKind(sheetName) === 'fisico'
        ? buildPhysicalLaudoRecords(data, sheetName)
        : buildLibraryLaudoRecords(data, sheetName);
}

function buildPhysicalLaudoRecords(data, sheetName) {
    const records = [];
    let currentRecord = null;
    let columnHeaders = {};

    data.forEach((row, rowIndex) => {
        if (!rowHasContent(row)) return;

        if (isPhysicalHeaderRow(row)) {
            columnHeaders = getLaudoColumnHeaders(row);
            return;
        }

        const title = cleanCellText(row[0] || '');
        if (title) {
            currentRecord = createLaudoRecord(title, rowIndex, 0, row, sheetName, '', columnHeaders);
            records.push(currentRecord);
        }

        if (currentRecord) {
            currentRecord.rows.push({ row, rowIndex });
        }
    });

    return records;
}

function buildLibraryLaudoRecords(data, sheetName) {
    const records = [];
    let currentSection = '';
    let groupedRecord = null;
    let generalFlowRecord = null;
    let columnHeaders = {};

    data.forEach((row, rowIndex) => {
        if (!rowHasContent(row)) return;

        if (isLaudoMajorSectionRow(row, rowIndex, sheetName)) {
            currentSection = cleanCellText(row[0] || '');
            columnHeaders = {};
            generalFlowRecord = null;

            if (shouldGroupLibrarySection(currentSection)) {
                groupedRecord = createLaudoRecord(currentSection, rowIndex, 0, row, sheetName, currentSection, {});
                records.push(groupedRecord);
            } else {
                groupedRecord = null;
            }
            return;
        }

        if (isLaudoColumnHeaderRow(row, rowIndex, sheetName)) {
            columnHeaders = getLaudoColumnHeaders(row);
            return;
        }

        if (!currentSection && isNumberedCriterionRow(row)) {
            currentSection = 'Análises importantes para enquadramento';
            groupedRecord = createLaudoRecord(currentSection, rowIndex, 0, row, sheetName, currentSection, {});
            records.push(groupedRecord);
        }

        if (groupedRecord) {
            groupedRecord.rows.push({ row, rowIndex });
            return;
        }

        const titleCell = getFirstNonEmptyCell(row);
        if (!titleCell) return;

        if (titleCell.index > 0) {
            if (!generalFlowRecord) {
                const title = currentSection
                    ? `${currentSection} - Critérios gerais`
                    : 'Critérios gerais de enquadramento';
                generalFlowRecord = createLaudoRecord(title, rowIndex, titleCell.index, row, sheetName, currentSection, columnHeaders);
                records.push(generalFlowRecord);
            }
            generalFlowRecord.rows.push({ row, rowIndex });
            return;
        }

        generalFlowRecord = null;
        const record = createLaudoRecord(titleCell.value, rowIndex, titleCell.index, row, sheetName, currentSection, columnHeaders);
        record.rows.push({ row, rowIndex });
        records.push(record);
    });

    return records;
}

function createLaudoRecord(title, rowIndex, colIndex, row, sheetName, context, headers) {
    return {
        title,
        titleCell: { value: title, rowIndex, colIndex },
        primaryIndex: rowIndex,
        primaryRow: row,
        sheetName,
        context: context || '',
        headers: { ...(headers || {}) },
        rows: []
    };
}

function getLaudoRowCells(row, rowIndex, sheetName = currentSheet, includeEmpty = false) {
    const columnCount = includeEmpty
        ? getSheetColumnCount(SHEET_DATA[sheetName] || [row])
        : row.length;

    return Array.from({ length: columnCount }, (_, colIndex) => {
        const value = row[colIndex] || '';
        return {
            value: (value || '').toString(),
            rowIndex,
            colIndex,
            style: getCellStyle(sheetName, rowIndex, colIndex)
        };
    }).filter(cell => includeEmpty || cleanCellText(cell.value).length > 0);
}

function getLaudoColumnHeaders(row) {
    const headers = {};
    row.forEach((value, colIndex) => {
        const text = cleanCellText(value || '');
        if (text) headers[colIndex] = text;
    });
    return headers;
}

function isPhysicalHeaderRow(row) {
    const first = normalizeText(row[0] || '');
    const values = row.map(value => normalizeText(value)).filter(Boolean);
    return first === 'risco'
        || (!first && values.length === 1 && values[0] === 'analise');
}

function isLaudoMajorSectionRow(row, rowIndex, sheetName) {
    const cells = getLaudoRowCells(row, rowIndex, sheetName);
    if (cells.length !== 1 || cells[0].colIndex !== 0) return false;

    const text = normalizeText(cells[0].value);
    const fill = (cells[0].style?.bg || '').toUpperCase();
    const knownHeading = [
        'analises importantes para enquadramento',
        'conceito permanencia',
        'eficacias das medidas de controle',
        'agentes quimicos cancerigenos',
        'aposentadoria especial',
        'insalubridade grau maximo',
        'insalubridade grau medio'
    ].some(term => text.includes(term));

    return knownHeading || ['#AFABAB', '#AEAAAA', '#FF0000', '#385724', '#375623', '#3B3838'].includes(fill);
}

function shouldGroupLibrarySection(sectionTitle) {
    const normalized = normalizeText(sectionTitle);
    return [
        'analises importantes',
        'conceito permanencia',
        'eficacias das medidas de controle',
        'agentes quimicos cancerigenos'
    ].some(term => normalized.includes(term));
}

function isLaudoColumnHeaderRow(row, rowIndex, sheetName) {
    const cells = getLaudoRowCells(row, rowIndex, sheetName);
    if (!cells.length) return false;

    const values = cells.map(cell => normalizeText(cell.value));
    const headerTerms = [
        'atividade', 'trabalhador executa essa atividade', 'listagem', 'definicao',
        'agentes quimicos', 'possui limite de tolerancia na nr-15', 'enquadramento',
        'conceito e enquadramento', 'onde encontrar que o agente quimico e cancerigeno'
    ];
    const termMatch = values.some(value => headerTerms.some(term => value === term));
    const styledCells = cells.filter(cell => ['#181717', '#AFABAB', '#AEAAAA', '#BDD7EE'].includes((cell.style?.bg || '').toUpperCase()));

    return termMatch && styledCells.length >= Math.min(1, cells.length);
}

function isNumberedCriterionRow(row) {
    const first = cleanCellText(row[0] || '');
    return /^\d+\.\s+/.test(first);
}

function laudoRecordMatchesFilters(record) {
    const kind = getLaudoKind(currentSheet);
    if (riskTypeFilter && kind !== riskTypeFilter) return false;

    if (riskNameTerm && !normalizeText(record.title).includes(normalizeText(riskNameTerm))) {
        return false;
    }

    if (searchTerm) {
        const term = normalizeText(searchTerm);
        const matches = record.rows.some(({ row }) => {
            const cells = fieldFilter === 'all' ? row : [row[Number(fieldFilter)] || ''];
            return cells.some(cell => normalizeText(cell).includes(term));
        }) || normalizeText(record.title).includes(term);
        if (!matches) return false;
    }

    return true;
}

function detectLaudoSectionTitle(text, context = '') {
    const normalized = normalizeText(`${context} ${text}`);

    if (normalized.includes('analises importantes')) {
        return 'Análises importantes para enquadramento';
    }
    if (normalized.includes('conceito permanencia') || normalized.includes('exposicao permanente')) {
        return 'Conceito de permanência';
    }
    if (normalized.includes('eficacia') || normalized.includes('medidas de controle') || normalized.includes('neutraliza')) {
        return 'Eficácia das medidas de controle';
    }
    if (normalized.includes('legislacao trabalhista')) {
        return 'Legislação trabalhista';
    }
    if (normalized.includes('legislacao previdenciaria')) {
        return 'Legislação previdenciária';
    }
    if (normalized.includes('parecer tecnico')) {
        return 'Parecer técnico';
    }
    if (normalized.includes('aposentadoria') || normalized.includes('previdenci') || normalized.includes('anexo iv')) {
        return 'Parecer previdenciário / Aposentadoria especial';
    }
    if (normalized.includes('insalubr') || normalized.includes('trabalhista') || normalized.includes('adicional')) {
        return 'Parecer trabalhista / Insalubridade';
    }
    if (normalized.includes('observa') || normalized.includes('referencia') || normalized.includes('onde encontrar')
        || normalized.includes('nota tecnica') || normalized.includes('acgih') || normalized.includes('http')) {
        return 'Observações';
    }
    if (normalized.includes('possibilidade') || normalized.includes('inconclus') || normalized.includes('enquadramento')
        || normalized.includes('resultado acima') || normalized.includes('resultado abaixo')) {
        return 'Cenários';
    }
    return 'Critério de análise';
}

function isLaudoBranchLabel(value) {
    const normalized = normalizeText(value);
    return ['sim', 'nao', 'possibilidade 1', 'possibilidade 2', 'enquadramento', 'inconclusivo', 'observacao'].includes(normalized);
}

function isLaudoQuestion(value) {
    const normalized = normalizeText(value);
    return value.includes('?')
        || normalized.startsWith('foi realizada')
        || normalized.startsWith('a empresa')
        || normalized.startsWith('analise tecnica')
        || normalized.startsWith('resultado');
}

function renderLaudoCards(container, data) {
    const records = buildLaudoRecords(data, currentSheet);
    const filteredRecords = records.filter(laudoRecordMatchesFilters);

    if (!filteredRecords.length) {
        container.innerHTML = `
            <div class="no-results">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
                    <circle cx="11" cy="11" r="8"/>
                    <line x1="21" y1="21" x2="16.65" y2="16.65"/>
                </svg>
                <h3>Nenhum tópico de laudo encontrado</h3>
                <p>Tente buscar com termos diferentes, trocar o campo ou limpar os filtros.</p>
            </div>`;
        updateCounts(0, records.length);
        return;
    }

    const list = document.createElement('div');
    list.className = `laudo-card-list${isAdmin ? ' admin-mode' : ''}`;
    filteredRecords.forEach(record => list.appendChild(renderLaudoCard(record)));

    container.innerHTML = '';
    container.appendChild(list);
    updateCounts(filteredRecords.length, records.length);
}

function renderLaudoCard(record) {
    const kind = getLaudoKind(record.sheetName);
    const card = document.createElement('details');
    card.className = `laudo-card${kind ? ` risk-${kind}` : ''}`;
    card.dataset.riskType = kind;

    const summary = document.createElement('summary');
    summary.className = 'laudo-summary';

    const main = document.createElement('div');
    main.className = 'laudo-summary-main';

    const title = document.createElement('div');
    title.className = 'laudo-summary-title';
    let titleGetter = () => record.title;

    if (isAdmin) {
        const editor = document.createElement('textarea');
        editor.className = 'cell-editor laudo-title-editor';
        editor.value = record.title;
        editor.dataset.row = record.titleCell.rowIndex;
        editor.dataset.col = record.titleCell.colIndex;
        editor.rows = 2;
        editor.onclick = event => event.stopPropagation();
        editor.onkeydown = event => event.stopPropagation();
        applyCellStyle(editor, getCellStyle(currentSheet, record.titleCell.rowIndex, record.titleCell.colIndex), { includeBackground: true });
        title.appendChild(editor);
        titleGetter = () => editor.value;
    } else {
        title.innerHTML = formatStyledCellContent(record.title, record.titleCell.rowIndex, record.titleCell.colIndex);
        applyCellStyle(title, getCellStyle(currentSheet, record.titleCell.rowIndex, record.titleCell.colIndex));
    }
    main.appendChild(title);

    const meta = document.createElement('div');
    meta.className = 'laudo-summary-meta';
    meta.appendChild(createLaudoBadge(getLaudoTypeLabel(record.sheetName), 'type'));
    meta.appendChild(createLaudoBadge(kind === 'fisico' ? 'Fluxo de enquadramento técnico' : 'Critérios de análise'));
    if (record.context && normalizeText(record.context) !== normalizeText(record.title)) {
        meta.appendChild(createLaudoBadge(record.context));
    }
    main.appendChild(meta);

    const actions = document.createElement('div');
    actions.className = 'laudo-summary-actions';
    actions.appendChild(createCopyButton(titleGetter));

    if (isAdmin) {
        actions.appendChild(createLaudoDeleteButton(record));
    }

    const chevron = document.createElement('button');
    chevron.type = 'button';
    chevron.className = 'laudo-chevron';
    chevron.title = 'Abrir detalhes';
    chevron.setAttribute('aria-label', 'Abrir detalhes');
    chevron.innerHTML = `
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round">
            <polyline points="6 9 12 15 18 9"></polyline>
        </svg>`;
    chevron.onclick = event => {
        event.preventDefault();
        event.stopPropagation();
        card.open = !card.open;
    };
    actions.appendChild(chevron);

    summary.appendChild(main);
    summary.appendChild(actions);
    card.appendChild(summary);
    card.addEventListener('toggle', () => {
        chevron.title = card.open ? 'Fechar detalhes' : 'Abrir detalhes';
        chevron.setAttribute('aria-label', chevron.title);
        if (card.open && !card.querySelector('.laudo-body')) {
            card.appendChild(kind === 'fisico' ? renderDecisionFlow(record) : renderScenarioGrid(record));
        }
    });

    return card;
}

function createLaudoBadge(text, extraClass = '') {
    const badge = document.createElement('span');
    badge.className = `laudo-badge${extraClass ? ` ${extraClass}` : ''}`;
    badge.textContent = text;
    return badge;
}

function createLaudoDeleteButton(record) {
    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'copy-cell risk-delete-button';
    button.title = 'Remover tópico';
    button.setAttribute('aria-label', 'Remover tópico');
    button.innerHTML = `
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
            <polyline points="3 6 5 6 21 6"></polyline>
            <path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"></path>
            <path d="M10 11v6"></path>
            <path d="M14 11v6"></path>
            <path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"></path>
        </svg>`;
    button.onclick = event => {
        event.preventDefault();
        event.stopPropagation();
        deleteLaudoRecord(record);
    };
    return button;
}

function getLaudoCellLabel(record, cell, activeBranch = {}) {
    const branch = activeBranch[cell.colIndex];
    if (branch) return branch;

    const header = cleanCellText(record.headers[cell.colIndex] || '');
    if (header && !['risco', 'tópico', 'analise', 'análise'].includes(normalizeText(header))) {
        return header;
    }

    const value = cleanCellText(cell.value);
    const normalizedValue = normalizeText(value);
    const criterionMatch = value.match(/^(\d+)\.\s+/);

    if (criterionMatch) return `Critério ${criterionMatch[1]}`;
    if (isLaudoQuestion(value)) return 'Pergunta de decisão';
    if (normalizedValue.includes('legislacao trabalhista') || normalizedValue.startsWith('trabalhista -')) {
        return 'Legislação trabalhista';
    }
    if (normalizedValue.includes('legislacao previdenciaria') || normalizedValue.startsWith('previdenciario -')) {
        return 'Legislação previdenciária';
    }
    if (normalizedValue.includes('parecer tecnico')) return 'Parecer técnico';
    if (normalizedValue.includes('observacao')) return 'Observação';
    if (cell.colIndex === 0) return 'Tópico';
    return 'Análise técnica';
}

function isLaudoMarker(value, marker) {
    return normalizeText(value) === normalizeText(marker);
}

function renderDecisionFlow(record) {
    const body = document.createElement('div');
    body.className = 'laudo-body';

    const flowRows = [];
    const sections = new Map();
    const activeBranch = {};
    let stage = 'Critério de análise';

    const addSectionEntry = (title, entry) => {
        if (!sections.has(title)) sections.set(title, []);
        sections.get(title).push(entry);
    };

    record.rows.forEach(({ row, rowIndex }) => {
        const cells = getLaudoRowCells(row, rowIndex, currentSheet, isAdmin)
            .filter(cell => !(cell.rowIndex === record.titleCell.rowIndex && cell.colIndex === record.titleCell.colIndex));
        if (!cells.length) return;

        if (cells.some(cell => isLaudoMarker(cell.value, 'INSALUBRIDADE'))) stage = 'Parecer trabalhista / Insalubridade';
        if (cells.some(cell => isLaudoMarker(cell.value, 'APOSENTADORIA ESPECIAL'))) stage = 'Parecer previdenciário / Aposentadoria especial';

        const flowEntries = [];

        cells.forEach(cell => {
            if (isLaudoMarker(cell.value, 'INSALUBRIDADE') || isLaudoMarker(cell.value, 'APOSENTADORIA ESPECIAL')) return;

            const header = cleanCellText(record.headers[cell.colIndex] || '');
            const normalizedHeader = normalizeText(header);
            const branchLabel = isLaudoBranchLabel(cell.value);
            const label = branchLabel ? 'Ramo de decisão' : getLaudoCellLabel(record, cell, activeBranch);
            const normalizedBranch = normalizeText(activeBranch[cell.colIndex] || '');

            if (branchLabel) activeBranch[cell.colIndex] = cell.value;

            let sectionTitle = stage;
            if (normalizedHeader.includes('aposentadoria')) {
                sectionTitle = 'Parecer previdenciário / Aposentadoria especial';
            } else if (normalizedHeader.includes('insalubr')) {
                sectionTitle = 'Parecer trabalhista / Insalubridade';
            } else if (normalizedBranch === 'observacao' || isLaudoMarker(cell.value, 'OBSERVAÇÃO')) {
                sectionTitle = 'Observações';
            } else if (stage === 'Critério de análise' || branchLabel || isLaudoQuestion(cell.value)) {
                sectionTitle = 'Fluxo de decisão';
            }

            const entry = { ...cell, label, branchLabel };
            if (sectionTitle === 'Fluxo de decisão') {
                flowEntries.push(entry);
            } else {
                addSectionEntry(sectionTitle, entry);
            }
        });

        if (flowEntries.length) flowRows.push(flowEntries);
    });

    if (flowRows.length) {
        const flow = document.createElement('div');
        flow.className = 'laudo-flow';
        flowRows.forEach(entries => flow.appendChild(renderLaudoFlowStep(entries)));
        body.appendChild(renderLaudoSection('Critério de análise e cenários', flow, flowRows.length));
    }

    getLaudoSectionOrder(sections).forEach(title => {
        const grid = document.createElement('div');
        grid.className = 'laudo-section-grid';
        sections.get(title).forEach(entry => {
            grid.appendChild(renderLaudoTextSection(entry.label, entry.value, entry.rowIndex, entry.colIndex, 'laudo-outcome'));
        });
        body.appendChild(renderLaudoSection(title, grid, sections.get(title).length));
    });

    return body;
}

function renderLaudoFlowStep(entries) {
    const step = document.createElement('div');
    step.className = `laudo-step${entries.some(entry => isLaudoQuestion(entry.value)) ? ' laudo-step-question' : ''}`;

    if (entries.length === 1) {
        const entry = entries[0];
        const title = document.createElement('div');
        title.className = 'laudo-step-title';
        title.textContent = entry.label;
        step.appendChild(title);
        step.appendChild(createLaudoCellContent(entry));
        step.classList.add('has-copy');
        const copyRow = document.createElement('div');
        copyRow.className = 'laudo-copy-row';
        copyRow.appendChild(createCopyButton(() => getLaudoEditorValue(step, entry.value)));
        step.appendChild(copyRow);
        return step;
    }

    const grid = document.createElement('div');
    grid.className = 'laudo-branch-grid';
    entries.forEach(entry => {
        const branch = document.createElement('div');
        const normalized = normalizeText(entry.value);
        branch.className = `laudo-branch has-copy${normalized === 'sim' ? ' laudo-branch-sim' : ''}${normalized === 'nao' ? ' laudo-branch-nao' : ''}`;

        const label = document.createElement('div');
        label.className = 'laudo-branch-label';
        label.textContent = entry.label;
        branch.appendChild(label);
        branch.appendChild(createLaudoCellContent(entry));

        const copyRow = document.createElement('div');
        copyRow.className = 'laudo-copy-row';
        copyRow.appendChild(createCopyButton(() => getLaudoEditorValue(branch, entry.value)));
        branch.appendChild(copyRow);
        grid.appendChild(branch);
    });
    step.appendChild(grid);
    return step;
}

function renderScenarioGrid(record) {
    const body = document.createElement('div');
    body.className = 'laudo-body';
    const sections = new Map();

    record.rows.forEach(({ row, rowIndex }) => {
        getLaudoRowCells(row, rowIndex, currentSheet, isAdmin)
            .filter(cell => !(cell.rowIndex === record.titleCell.rowIndex && cell.colIndex === record.titleCell.colIndex))
            .forEach(cell => {
                const label = getLaudoCellLabel(record, cell);
                const sectionTitle = getLibraryLaudoSectionTitle(record, label, cell.value);
                if (!sections.has(sectionTitle)) sections.set(sectionTitle, []);
                sections.get(sectionTitle).push({ ...cell, label });
            });
    });

    getLaudoSectionOrder(sections).forEach(title => {
        const grid = document.createElement('div');
        grid.className = 'laudo-section-grid';
        sections.get(title).forEach(entry => {
            grid.appendChild(renderLaudoTextSection(entry.label, entry.value, entry.rowIndex, entry.colIndex));
        });
        body.appendChild(renderLaudoSection(title, grid, sections.get(title).length));
    });

    return body;
}

function getLibraryLaudoSectionTitle(record, label, value) {
    const context = cleanCellText(record.context || '');
    const normalizedContext = normalizeText(context);
    const contextualSections = [
        'analises importantes',
        'conceito permanencia',
        'eficacias das medidas de controle',
        'agentes quimicos cancerigenos'
    ];

    if (contextualSections.some(section => normalizedContext.includes(section))) {
        return detectLaudoSectionTitle(context, label);
    }

    return detectLaudoSectionTitle(`${label} ${value}`, context);
}

function getLaudoSectionOrder(sections) {
    const preferred = [
        'Critério de análise',
        'Análises importantes para enquadramento',
        'Conceito de permanência',
        'Cenários',
        'Legislação trabalhista',
        'Parecer trabalhista / Insalubridade',
        'Legislação previdenciária',
        'Parecer previdenciário / Aposentadoria especial',
        'Eficácia das medidas de controle',
        'Parecer técnico',
        'Observações'
    ];

    return [...sections.keys()].sort((a, b) => {
        const aIndex = preferred.indexOf(a);
        const bIndex = preferred.indexOf(b);
        return (aIndex < 0 ? preferred.length : aIndex) - (bIndex < 0 ? preferred.length : bIndex);
    });
}

function renderLaudoSection(title, content, count) {
    const section = document.createElement('section');
    section.className = 'laudo-section';

    const header = document.createElement('div');
    header.className = 'laudo-section-header';
    const heading = document.createElement('h4');
    heading.textContent = title;
    header.appendChild(heading);

    const counter = document.createElement('span');
    counter.className = 'laudo-section-count';
    counter.textContent = `${count} ${count === 1 ? 'bloco' : 'blocos'}`;
    header.appendChild(counter);

    section.appendChild(header);
    section.appendChild(content);
    return section;
}

function renderLaudoTextSection(title, content, rowIndex, colIndex, extraClass = '') {
    const block = document.createElement('div');
    block.className = `laudo-text-block${extraClass ? ` ${extraClass}` : ''}${cleanCellText(content) ? ' has-copy' : ''}`;

    const heading = document.createElement('div');
    heading.className = 'laudo-text-title';
    heading.textContent = title;
    block.appendChild(heading);
    block.appendChild(createLaudoCellContent({ value: content, rowIndex, colIndex }));

    if (cleanCellText(content)) {
        const copyRow = document.createElement('div');
        copyRow.className = 'laudo-copy-row';
        copyRow.appendChild(createCopyButton(() => getLaudoEditorValue(block, content)));
        block.appendChild(copyRow);
    }

    return block;
}

function createLaudoCellContent(cell) {
    if (isAdmin && cell.colIndex >= 0) {
        const editor = document.createElement('textarea');
        editor.className = 'cell-editor';
        editor.value = cell.value;
        editor.dataset.row = cell.rowIndex;
        editor.dataset.col = cell.colIndex;
        editor.rows = Math.max(3, Math.min(14, (cell.value.match(/\n/g) || []).length + 2));
        applyCellStyle(editor, getCellStyle(currentSheet, cell.rowIndex, cell.colIndex), { includeBackground: true });
        return editor;
    }

    const content = document.createElement('div');
    content.className = 'laudo-text-content';
    content.innerHTML = formatStyledCellContent(cell.value, cell.rowIndex, cell.colIndex);
    applyCellStyle(content, getCellStyle(currentSheet, cell.rowIndex, cell.colIndex));
    return content;
}

function getLaudoEditorValue(container, fallbackValue) {
    const editor = container.querySelector('.cell-editor');
    return editor ? editor.value : fallbackValue;
}

function createCopyButton(valueOrGetter, extraClass = '') {
    const copyButton = document.createElement('button');
    copyButton.type = 'button';
    copyButton.className = `copy-cell${extraClass ? ` ${extraClass}` : ''}`;
    copyButton.title = 'Copiar conteúdo';
    copyButton.setAttribute('aria-label', 'Copiar conteúdo');
    copyButton.innerHTML = COPY_ICON;
    copyButton.onclick = (event) => {
        event.preventDefault();
        event.stopPropagation();
        const value = typeof valueOrGetter === 'function' ? valueOrGetter() : valueOrGetter;
        copyCellContent(value, copyButton);
    };
    return copyButton;
}

function formatRiskValue(value) {
    const text = (value || '').toString();
    if (!text.trim()) {
        return '<span class="risk-empty">--</span>';
    }
    return highlightText(escapeHtml(text));
}

function createRiskValueCell(value, rowIndex, colIndex, options = {}) {
    const td = document.createElement('td');
    td.className = 'risk-value-cell';
    if (options.colSpan) td.colSpan = options.colSpan;

    const cellValue = (value || '').toString();
    const cellStyle = getCellStyle(currentSheet, rowIndex, colIndex);

    if (isAdmin && colIndex >= 0) {
        const wrap = document.createElement('div');
        wrap.className = 'risk-editor-wrap';

        const textarea = document.createElement('textarea');
        textarea.className = 'cell-editor';
        textarea.value = cellValue;
        textarea.dataset.row = rowIndex;
        textarea.dataset.col = colIndex;
        const lines = (cellValue.match(/\n/g) || []).length + 1;
        textarea.rows = Math.max(2, Math.min(12, lines));
        applyCellStyle(textarea, cellStyle, { includeBackground: true });
        wrap.appendChild(textarea);

        if (cellValue.trim()) {
            wrap.appendChild(createCopyButton(() => textarea.value));
        }

        td.appendChild(wrap);
        return td;
    }

    if (cellValue.trim()) td.classList.add('has-copy');

    const text = document.createElement('div');
    text.className = 'risk-value-text';
    if (options.contentNode) {
        text.appendChild(options.contentNode);
    } else {
        text.innerHTML = formatStyledCellContent(cellValue, rowIndex, colIndex);
    }
    td.appendChild(text);
    applyCellStyle(text, cellStyle);

    if (cellValue.trim()) {
        td.appendChild(createCopyButton(cellValue));
    }

    return td;
}

function appendRiskSection(table, title, className = 'risk-section-row') {
    const row = document.createElement('tr');
    row.className = className;
    const th = document.createElement('th');
    th.colSpan = 4;
    th.textContent = title;
    row.appendChild(th);
    table.appendChild(row);
}

function appendRiskFieldRow(table, label, value, rowIndex, colIndex) {
    const row = document.createElement('tr');
    const labelCell = document.createElement('td');
    labelCell.className = 'risk-label-cell';
    labelCell.textContent = label;
    row.appendChild(labelCell);
    row.appendChild(createRiskValueCell(value, rowIndex, colIndex, { colSpan: 3 }));
    table.appendChild(row);
}

function parseRiskMatrix(value) {
    const text = (value || '').toString();
    const readLine = (label) => {
        const regex = new RegExp(`${label}:\\s*([^\\n]+)`, 'i');
        const match = text.match(regex);
        return match ? match[1].trim() : '';
    };

    return {
        probability: readLine('Probabilidade'),
        severity: readLine('Gravidade'),
        level: readLine('Nivel de risco') || readLine('Nível de risco'),
        classification: readLine('Classificacao') || readLine('Classificação')
    };
}

function createRiskMatrixContent(value) {
    const matrix = parseRiskMatrix(value);
    const wrapper = document.createElement('div');
    const grid = document.createElement('div');
    grid.className = 'risk-matrix-grid';

    [
        ['Probabilidade', matrix.probability],
        ['Gravidade', matrix.severity],
        ['NÍVEL DE RISCO', matrix.level],
        ['Classificação', matrix.classification]
    ].forEach(([label, itemValue]) => {
        const item = document.createElement('div');
        item.className = 'risk-matrix-item';

        const labelEl = document.createElement('div');
        labelEl.className = 'risk-matrix-label';
        labelEl.textContent = label;
        item.appendChild(labelEl);

        const valueEl = document.createElement('div');
        valueEl.className = 'risk-matrix-value';
        valueEl.innerHTML = formatRiskValue(itemValue);
        item.appendChild(valueEl);

        grid.appendChild(item);
    });

    wrapper.appendChild(grid);

    if ((value || '').toString().trim()) {
        const raw = document.createElement('div');
        raw.className = 'risk-matrix-raw';
        raw.innerHTML = highlightText(escapeHtml(value));
        wrapper.appendChild(raw);
    }

    return wrapper;
}

function appendRiskMatrixRow(table, value, rowIndex, colIndex) {
    const row = document.createElement('tr');
    const labelCell = document.createElement('td');
    labelCell.className = 'risk-label-cell';
    labelCell.textContent = 'Matriz de risco';
    row.appendChild(labelCell);

    if (isAdmin && colIndex >= 0) {
        row.appendChild(createRiskValueCell(value, rowIndex, colIndex, { colSpan: 3 }));
    } else {
        row.appendChild(createRiskValueCell(value, rowIndex, colIndex, {
            colSpan: 3,
            contentNode: createRiskMatrixContent(value)
        }));
    }

    table.appendChild(row);
}

function renderRiskCards(container, filteredRows, config, data) {
    if (config.groupRows) {
        renderGroupedRiskCards(container, config, data);
        return;
    }

    const list = document.createElement('div');
    list.className = `risk-card-list${isAdmin ? ' admin-mode' : ''}`;
    let rendered = 0;

    for (let r = config.startIndex ?? 1; r < filteredRows.length; r++) {
        const originalIndex = filteredRows[r].idx;
        const rowData = filteredRows[r].row;
        const riskTitle = cleanCellText(rowData[config.riskIndex] || '');

        if (!rowHasContent(rowData) || !riskTitle) continue;

        const riskType = getRiskTypeForRow(currentSheet, rowData, originalIndex);
        list.appendChild(renderRiskCard(rowData, originalIndex, config, riskType, riskTitle));
        rendered++;
    }

    if (!rendered) {
        container.innerHTML = `
            <div class="no-results">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
                    <circle cx="11" cy="11" r="8"/>
                    <line x1="21" y1="21" x2="16.65" y2="16.65"/>
                </svg>
                <h3>Nenhum resultado encontrado</h3>
                <p>Tente buscar com termos diferentes, trocar o campo ou limpar os filtros.</p>
            </div>`;
        updateCounts(0, countRiskDetailRows(data, config));
        return;
    }

    container.innerHTML = '';
    container.appendChild(list);
    updateCounts(rendered, countRiskDetailRows(data, config));
}

function renderGroupedRiskCards(container, config, data) {
    const records = buildGroupedRiskRecords(data, config);
    const filteredRecords = records.filter(record => recordMatchesFilters(record, config));
    const list = document.createElement('div');
    list.className = `risk-card-list${isAdmin ? ' admin-mode' : ''}`;

    filteredRecords.forEach(record => {
        const riskType = getRiskTypeForRow(currentSheet, record.primaryRow, record.primaryIndex);
        list.appendChild(renderRiskCard(record.primaryRow, record.primaryIndex, config, riskType, record.title, record));
    });

    if (!filteredRecords.length) {
        container.innerHTML = `
            <div class="no-results">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
                    <circle cx="11" cy="11" r="8"/>
                    <line x1="21" y1="21" x2="16.65" y2="16.65"/>
                </svg>
                <h3>Nenhum resultado encontrado</h3>
                <p>Tente buscar com termos diferentes, trocar o campo ou limpar os filtros.</p>
            </div>`;
        updateCounts(0, records.length);
        return;
    }

    container.innerHTML = '';
    container.appendChild(list);
    updateCounts(filteredRecords.length, records.length);
}

function renderRiskCard(rowData, rowIndex, config, riskType, riskTitle, record = null) {
    const card = document.createElement('details');
    card.className = `risk-card${riskType ? ` risk-${riskType}` : ''}`;
    card.dataset.riskType = riskType || '';

    const summary = document.createElement('summary');
    const main = document.createElement('div');
    main.className = 'risk-summary-main';

    const title = document.createElement('div');
    title.className = 'risk-summary-title';
    title.innerHTML = formatStyledCellContent(riskTitle, rowIndex, config.riskIndex);
    applyCellStyle(title, getCellStyle(currentSheet, rowIndex, config.riskIndex));
    main.appendChild(title);

    const meta = document.createElement('div');
    meta.className = 'risk-summary-meta';
    meta.textContent = getRiskGroupLabel(rowData, config, riskType);
    applyCellStyle(meta, getCellStyle(currentSheet, rowIndex, config.groupIndex));
    main.appendChild(meta);

    const actions = document.createElement('div');
    actions.className = 'risk-summary-actions';
    actions.appendChild(createCopyButton(riskTitle));

    if (isAdmin) {
        const deleteButton = document.createElement('button');
        deleteButton.type = 'button';
        deleteButton.className = 'copy-cell risk-delete-button';
        deleteButton.title = 'Remover risco';
        deleteButton.setAttribute('aria-label', 'Remover risco');
        deleteButton.innerHTML = `
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
                <polyline points="3 6 5 6 21 6"></polyline>
                <path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"></path>
                <path d="M10 11v6"></path>
                <path d="M14 11v6"></path>
                <path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"></path>
            </svg>`;
        deleteButton.onclick = (event) => {
            event.preventDefault();
            event.stopPropagation();
            deleteRiskRecord(rowIndex, riskTitle);
        };
        actions.appendChild(deleteButton);
    }

    const toggle = document.createElement('span');
    toggle.className = 'risk-toggle';
    toggle.innerHTML = `
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
            <polyline points="6 9 12 15 18 9"></polyline>
        </svg>`;
    actions.appendChild(toggle);

    summary.appendChild(main);
    summary.appendChild(actions);
    card.appendChild(summary);

    const detail = document.createElement('div');
    detail.className = 'risk-detail';

    const table = document.createElement('table');
    table.className = 'risk-spec-table';

    appendRiskSection(table, `Especificação dos perigos/fatores de risco - ${currentSheet}`, 'risk-title-row');
    appendRiskSection(table, 'Identificação');

    const headingRow = document.createElement('tr');
    headingRow.className = 'risk-heading-row risk-identity-heading';
    ['Grupo', 'Perigo/Fator de Risco'].forEach((label, index) => {
        const th = document.createElement('th');
        th.colSpan = index === 0 ? 1 : 3;
        th.textContent = label;
        headingRow.appendChild(th);
    });
    table.appendChild(headingRow);

    const identityRow = document.createElement('tr');
    identityRow.className = 'risk-identity-row';
    const groupHasSourceValue = config.groupIndex >= 0 && cleanCellText(rowData[config.groupIndex] || '').length > 0;
    identityRow.appendChild(createRiskValueCell(getRiskGroupLabel(rowData, config, riskType), rowIndex, groupHasSourceValue ? config.groupIndex : -1));
    identityRow.appendChild(createRiskValueCell(rowData[config.riskIndex] || '', rowIndex, config.riskIndex, { colSpan: 3 }));
    table.appendChild(identityRow);

    if (config.genericFields?.length) {
        appendRiskSection(table, record?.section || 'Informações da planilha');
        appendGenericRecordRows(table, record || {
            title: riskTitle,
            primaryIndex: rowIndex,
            primaryRow: rowData,
            rows: [{ row: rowData, rowIndex }]
        }, config);
        detail.appendChild(table);
        card.appendChild(detail);
        return card;
    }

    appendRiskFieldRow(table, 'Descrição', rowData[config.descriptionIndex] || '', rowIndex, config.descriptionIndex);
    appendRiskFieldRow(table, 'Fundamentação legal', rowData[config.legalIndex] || '', rowIndex, config.legalIndex);
    appendRiskFieldRow(table, 'Possíveis lesões ou agravos à saúde', rowData[config.injuriesIndex] || '', rowIndex, config.injuriesIndex);

    appendRiskSection(table, 'Avaliação');
    appendRiskFieldRow(table, 'Critério', 'Qualitativo', rowIndex, -1);
    appendRiskFieldRow(table, 'Perfil de exposição', rowData[config.profileIndex] || '', rowIndex, config.profileIndex);

    if (config.matrixIndex >= 0) {
        appendRiskMatrixRow(table, rowData[config.matrixIndex] || '', rowIndex, config.matrixIndex);
    }

    appendRiskSection(table, 'Prevenção e controle');
    appendRiskFieldRow(table, 'Ações necessárias', rowData[config.actionsIndex] || '', rowIndex, config.actionsIndex);

    detail.appendChild(table);
    card.appendChild(detail);

    return card;
}

function appendGenericRecordRows(table, record, config) {
    let added = 0;
    const headers = (SHEET_DATA[currentSheet] && SHEET_DATA[currentSheet][0]) || [];

    record.rows.forEach(({ row, rowIndex }) => {
        const cells = row
            .map((value, index) => ({
                index,
                value: (value || '').toString()
            }))
            .filter(cell => cleanCellText(cell.value).length > 0)
            .filter(cell => !(rowIndex === record.primaryIndex && cell.index === config.riskIndex))
            .filter(cell => !(rowIndex === record.primaryIndex && cell.index === config.groupIndex));

        cells.forEach(cell => {
            appendRiskFieldRow(table, getGenericCellLabel(headers, cell.index), cell.value, rowIndex, cell.index);
            added++;
        });
    });

    if (!added) {
        appendRiskFieldRow(table, 'Conteúdo', 'Sem informações adicionais na planilha.', record.primaryIndex, -1);
    }
}

function getGenericCellLabel(headers, cellIndex) {
    const header = cleanCellText(headers[cellIndex] || '');
    const normalizedHeader = normalizeText(header);

    if (header && !['risco', 'riscos', 'grupo'].includes(normalizedHeader)) {
        return header;
    }

    if (cellIndex === 0) return 'Tópico';
    if (cellIndex === 1 && normalizeText(currentSheet).startsWith('laudos-')) return 'Análise';
    if (cellIndex === 2 && normalizeText(currentSheet).startsWith('laudos-')) return 'Observação';

    return `Coluna ${cellIndex + 1}`;
}

function shouldHoldRiskSheetEmpty(config) {
    return Boolean(config && !isAdmin && !hasFilteringCriteria());
}

function renderRiskInitialState(container, data, config) {
    container.innerHTML = `
        <div class="no-results">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
                <circle cx="11" cy="11" r="8"/>
                <line x1="21" y1="21" x2="16.65" y2="16.65"/>
            </svg>
            <h3>Nenhum risco exibido</h3>
            <p>Pesquise pelo nome do risco ou selecione um tipo de risco para visualizar os registros.</p>
        </div>`;
    updateCounts(0, countRiskDetailRows(data, config));
}

function renderTable() {
    const container = document.getElementById('tableContainer');
    const data = SHEET_DATA[currentSheet];

    if (!data || data.length === 0) {
        container.innerHTML = '<div class="no-results"><h3>Nenhum dado encontrado</h3></div>';
        return;
    }

    if (isLaudoSheet(currentSheet)) {
        renderLaudoCards(container, data);
        return;
    }

    const riskDetailConfig = getRiskDetailConfig(data[0] || [], currentSheet);
    if (riskDetailConfig && shouldHoldRiskSheetEmpty(riskDetailConfig)) {
        renderRiskInitialState(container, data, riskDetailConfig);
        return;
    }

    const headerLimit = riskDetailConfig ? (riskDetailConfig.startIndex ?? 1) : 1;
    const filteredRows = data
        .map((row, idx) => ({ row, idx }))
        .filter(({ row, idx }) => idx < headerLimit || rowMatchesFilters(row, idx));

    if (riskDetailConfig) {
        renderRiskCards(container, filteredRows, riskDetailConfig, data);
        return;
    }

    const filteredData = filteredRows.map(item => item.row);

    if (filteredData.length <= 1) {
        container.innerHTML = `
            <div class="no-results">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
                    <circle cx="11" cy="11" r="8"/>
                    <line x1="21" y1="21" x2="16.65" y2="16.65"/>
                </svg>
                <h3>Nenhum resultado encontrado</h3>
                <p>Tente buscar com termos diferentes, trocar o campo ou limpar os filtros.</p>
            </div>`;
        updateCounts(0, Math.max(0, data.length - 1));
        return;
    }

    const table = document.createElement('table');
    table.className = isAdmin ? 'admin-mode' : '';

    const thead = document.createElement('thead');
    const headerRow = document.createElement('tr');
    const numCols = Math.max(...filteredData.map(r => r.length));
    const columnWidths = getColumnWidths(filteredData[0] || [], numCols);

    const colgroup = document.createElement('colgroup');
    for (let c = 0; c < numCols; c++) {
        const col = document.createElement('col');
        col.dataset.col = c;
        col.style.width = columnWidths[c];
        colgroup.appendChild(col);
    }
    table.appendChild(colgroup);

    for (let c = 0; c < numCols; c++) {
        const th = document.createElement('th');
        const headerText = filteredData[0] && filteredData[0][c] ? filteredData[0][c] : `Coluna ${c + 1}`;
        const headerStyle = getCellStyle(currentSheet, 0, c);
        th.style.width = columnWidths[c];
        applyCellStyle(th, headerStyle, { includeBackground: true });

        const label = document.createElement('span');
        label.innerHTML = formatStyledCellContent(headerText, 0, c, { emptyHtml: '' });
        th.appendChild(label);

        const resizer = document.createElement('span');
        resizer.className = 'col-resizer';
        resizer.title = 'Arraste para ajustar a largura da coluna';
        resizer.setAttribute('aria-hidden', 'true');
        resizer.onmousedown = (event) => startColumnResize(event, table, c);
        resizer.ondblclick = (event) => {
            event.preventDefault();
            resetColumnWidths();
        };
        th.appendChild(resizer);

        headerRow.appendChild(th);
    }
    thead.appendChild(headerRow);
    table.appendChild(thead);

    const tbody = document.createElement('tbody');
    const startRow = 1;

    for (let r = startRow; r < filteredRows.length; r++) {
        const row = document.createElement('tr');
        const originalIndex = filteredRows[r].idx;
        const rowData = filteredRows[r].row;
        const riskType = getRiskTypeForRow(currentSheet, rowData, originalIndex);

        if (riskType) {
            row.classList.add('risk-row', `risk-${riskType}`);
            row.dataset.riskType = riskType;
        }

        for (let c = 0; c < numCols; c++) {
            const td = document.createElement('td');
            const cellValue = rowData[c] || '';
            const cellStyle = getCellStyle(currentSheet, originalIndex, c);

            if (isAdmin) {
                const textarea = document.createElement('textarea');
                textarea.className = 'cell-editor';
                textarea.value = cellValue;
                textarea.dataset.row = originalIndex;
                textarea.dataset.col = c;
                const lines = (cellValue.match(/\n/g) || []).length + 1;
                textarea.rows = Math.max(2, Math.min(10, lines));
                applyCellStyle(textarea, cellStyle, { includeBackground: true });
                td.appendChild(textarea);
            } else {
                const box = document.createElement('div');
                box.className = 'cell-box';
                if (cellValue && cellValue.trim() !== '') box.classList.add('has-copy');
                applyCellStyle(box, cellStyle, { includeBackground: true, includeBorder: true });

                const div = document.createElement('div');
                div.className = 'cell-content';
                if (!cellValue || cellValue.trim() === '') {
                    div.innerHTML = '<span style="color: var(--text-muted); font-style: italic;">—</span>';
                } else {
                    div.innerHTML = formatStyledCellContent(cellValue, originalIndex, c);
                }
                applyCellStyle(div, cellStyle);

                box.appendChild(div);

                if (cellValue && cellValue.trim() !== '') {
                    const copyButton = document.createElement('button');
                    copyButton.type = 'button';
                    copyButton.className = 'copy-cell';
                    copyButton.title = 'Copiar conteúdo';
                    copyButton.setAttribute('aria-label', 'Copiar conteúdo');
                    copyButton.innerHTML = COPY_ICON;
                    copyButton.onclick = (event) => {
                        event.stopPropagation();
                        copyCellContent(cellValue, copyButton);
                    };
                    box.appendChild(copyButton);
                }

                td.appendChild(box);
            }

            row.appendChild(td);
        }

        tbody.appendChild(row);
    }

    table.appendChild(tbody);
    container.innerHTML = '';
    container.appendChild(table);

    updateCounts(filteredData.length - 1, data.length - 1);
}

// ============================================
// SEARCH
// ============================================
function handleSearch() {
    const input = document.getElementById('searchInput');
    searchTerm = input.value.trim();
    handleFilters();
}

function clearSearch() {
    document.getElementById('searchInput').value = '';
    searchTerm = '';
    updateFilterControls();
    renderTable();
}

function highlightText(text) {
    if (!searchTerm) return text;
    const term = escapeRegExp(searchTerm);
    const regex = new RegExp(`(${term})`, 'gi');
    return text.replace(regex, '<span class="highlight">$1</span>');
}

function escapeRegExp(string) {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// ============================================
// COUNTS
// ============================================
function updateCounts(filtered = null, total = null) {
    const data = SHEET_DATA[currentSheet];

    if (isLaudoSheet(currentSheet)) {
        const records = buildLaudoRecords(data || [], currentSheet);
        const t = total !== null ? total : records.length;
        const visibleCards = document.querySelectorAll('#tableContainer .laudo-card').length;
        const f = filtered !== null ? filtered : visibleCards;
        document.getElementById('resultCount').textContent = f;
        document.getElementById('totalCount').textContent = t;
        return;
    }

    const riskDetailConfig = getRiskDetailConfig((data && data[0]) || [], currentSheet);

    if (riskDetailConfig) {
        const t = total !== null ? total : countRiskDetailRows(data, riskDetailConfig);
        if (shouldHoldRiskSheetEmpty(riskDetailConfig)) {
            document.getElementById('resultCount').textContent = '0';
            document.getElementById('totalCount').textContent = t;
            return;
        }
        const visibleCards = document.querySelectorAll('#tableContainer .risk-card').length;
        const f = filtered !== null ? filtered : (visibleCards || (hasActiveFilters() ? 0 : t));
        document.getElementById('resultCount').textContent = f;
        document.getElementById('totalCount').textContent = t;
        return;
    }

    const t = total !== null ? total : Math.max(0, data.length - 1);
    const f = filtered !== null ? filtered : t;
    document.getElementById('resultCount').textContent = f;
    document.getElementById('totalCount').textContent = t;
}

// ============================================
// ADMIN MODE
// ============================================
function getSheetColumnCount(data) {
    return Math.max(...data.map(row => row.length), 1);
}

function ensureStyleGrid(sheetName, rowIndex, colCount) {
    if (!CELL_STYLES[sheetName]) CELL_STYLES[sheetName] = [];
    while (CELL_STYLES[sheetName].length <= rowIndex) {
        CELL_STYLES[sheetName].push(Array(colCount).fill(null));
    }
    while (CELL_STYLES[sheetName][rowIndex].length < colCount) {
        CELL_STYLES[sheetName][rowIndex].push(null);
    }
}

function addRiskRecord() {
    if (!isAdmin) return;

    const data = SHEET_DATA[currentSheet];

    if (isLaudoSheet(currentSheet)) {
        addLaudoRecord(data);
        return;
    }

    const config = getRiskDetailConfig((data && data[0]) || [], currentSheet);

    if (!data || !config) {
        showToast('Adicionar registro está disponível nas abas em modelo de risco.', 'info');
        return;
    }

    const colCount = getSheetColumnCount(data);
    const row = Array(colCount).fill('');
    const selectedType = riskTypeFilter || getSheetRiskType(currentSheet) || '';
    const riskStyle = getRiskStyleForType(selectedType);

    if (config.groupIndex >= 0 && selectedType) {
        row[config.groupIndex] = getRiskGroupNameForType(selectedType);
    }

    row[config.riskIndex] = 'Novo risco';
    data.push(row);

    const rowIndex = data.length - 1;
    ensureStyleGrid(currentSheet, rowIndex, colCount);

    if (riskStyle) {
        const baseStyle = { color: '#000000', bg: riskStyle.bg };
        CELL_STYLES[currentSheet][rowIndex][config.riskIndex] = baseStyle;
        if (config.groupIndex >= 0) {
            CELL_STYLES[currentSheet][rowIndex][config.groupIndex] = { color: '#000000' };
        }
    }

    buildRiskIndex();
    persistWorkbookSnapshot();
    renderTabs();
    renderFilters();
    renderTable();
    updateCounts();
    showToast('Registro adicionado. Edite os campos e salve.', 'success');
}

function addLaudoRecord(data) {
    if (!data) return;

    const colCount = getSheetColumnCount(data);
    const row = Array(colCount).fill('');
    row[0] = 'Novo tópico de laudo';
    data.push(row);

    const rowIndex = data.length - 1;
    ensureStyleGrid(currentSheet, rowIndex, colCount);

    const style = getRiskStyleForType(getLaudoKind(currentSheet));
    if (style) {
        CELL_STYLES[currentSheet][rowIndex][0] = { color: '#000000', bg: style.bg };
    }

    buildRiskIndex();
    persistWorkbookSnapshot();
    renderTabs();
    renderFilters();
    renderTable();
    updateCounts();
    showToast('Tópico adicionado. Abra o card, edite e salve.', 'success');
}

function deleteLaudoRecord(record) {
    if (!isAdmin || !record) return;
    const data = SHEET_DATA[currentSheet];
    if (!data) return;

    const rowIndexes = [
        record.titleCell.rowIndex,
        ...record.rows.map(item => item.rowIndex)
    ].filter(index => Number.isInteger(index));
    const deleteStart = Math.min(...rowIndexes);
    const deleteEnd = Math.max(...rowIndexes);
    const label = cleanCellText(record.title) || 'este tópico';

    if (!confirm(`Remover "${label}"?`)) return;

    data.splice(deleteStart, deleteEnd - deleteStart + 1);
    if (CELL_STYLES[currentSheet]) {
        CELL_STYLES[currentSheet].splice(deleteStart, deleteEnd - deleteStart + 1);
    }

    buildRiskIndex();
    persistWorkbookSnapshot();
    renderTabs();
    renderFilters();
    renderTable();
    updateCounts();
    showToast('Tópico removido.', 'success');
}

function deleteRiskRecord(rowIndex, riskTitle) {
    if (!isAdmin) return;

    const data = SHEET_DATA[currentSheet];
    const config = getRiskDetailConfig((data && data[0]) || [], currentSheet);
    if (!data || !config || rowIndex < (config.startIndex ?? 1) || rowIndex >= data.length) return;

    const label = cleanCellText(riskTitle) || 'este registro';
    if (!confirm(`Remover "${label}"?`)) return;

    let deleteStart = rowIndex;
    let deleteCount = 1;

    if (config.groupRows) {
        const record = buildGroupedRiskRecords(data, config).find(item => item.primaryIndex === rowIndex);
        if (record) {
            deleteStart = record.rows[0].rowIndex;
            const lastRow = record.rows[record.rows.length - 1].rowIndex;
            deleteCount = lastRow - deleteStart + 1;
        }
    }

    data.splice(deleteStart, deleteCount);
    if (CELL_STYLES[currentSheet]) CELL_STYLES[currentSheet].splice(deleteStart, deleteCount);

    buildRiskIndex();
    persistWorkbookSnapshot();
    renderTabs();
    renderFilters();
    renderTable();
    updateCounts();
    showToast('Registro removido.', 'success');
}

function openLogin() {
    if (isAdmin) {
        showToast('Você já está no modo administrador.', 'info');
        return;
    }
    document.getElementById('loginModal').classList.add('active');
    document.getElementById('adminPass').value = '';
    document.getElementById('adminPass').focus();
    document.getElementById('loginError').classList.remove('visible');
}

function closeLogin() {
    document.getElementById('loginModal').classList.remove('active');
}

function doLogin() {
    const user = document.getElementById('adminUser').value.trim();
    const pass = document.getElementById('adminPass').value;

    if (user === ADMIN_CREDENTIALS.user && pass === ADMIN_CREDENTIALS.pass) {
        isAdmin = true;
        closeLogin();
        document.getElementById('adminBar').classList.add('active');
        document.getElementById('btnAdmin').innerHTML = `
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/>
                <circle cx="12" cy="7" r="4"/>
            </svg>
            Modo Admin Ativo
        `;
        document.getElementById('btnAdmin').classList.remove('btn-ghost');
        document.getElementById('btnAdmin').classList.add('btn-primary');
        renderTable();
        showToast('Modo administrador ativado com sucesso!', 'success');
    } else {
        document.getElementById('loginError').classList.add('visible');
        document.getElementById('adminPass').value = '';
        document.getElementById('adminPass').focus();
    }
}

function exitAdmin() {
    isAdmin = false;
    document.getElementById('adminBar').classList.remove('active');
    document.getElementById('btnAdmin').innerHTML = `
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/>
            <circle cx="12" cy="7" r="4"/>
        </svg>
        Acesso Admin
    `;
    document.getElementById('btnAdmin').classList.add('btn-ghost');
    document.getElementById('btnAdmin').classList.remove('btn-primary');
    renderTable();
    showToast('Modo administrador desativado.', 'info');
}

async function saveChanges() {
    if (!isAdmin) return;

    const editors = document.querySelectorAll('.cell-editor');
    let changes = 0;
    const changedCells = [];

    editors.forEach(ed => {
        const r = parseInt(ed.dataset.row);
        const c = parseInt(ed.dataset.col);
        const newValue = ed.value;

        if (SHEET_DATA[currentSheet][r] && SHEET_DATA[currentSheet][r][c] !== newValue) {
            SHEET_DATA[currentSheet][r][c] = newValue;
            changedCells.push({
                sheetName: currentSheet,
                rowIndex: r,
                colIndex: c,
                value: newValue
            });
            changes++;
        }
    });

    if (changes > 0) {
        buildRiskIndex();
        renderFilters();
        persistWorkbookSnapshot();

        try {
            const savedRemote = await persistCellChanges(changedCells);
            const target = savedRemote ? 'e salva(s) no banco' : 'localmente';
            showToast(`${changes} célula(s) atualizada(s) ${target}.`, 'success');
            console.log('Data updated for sheet:', currentSheet);
        } catch (error) {
            console.error('Failed to persist changes:', error);
            showToast('Alterações aplicadas localmente, mas não salvas no Supabase.', 'error');
        }
    } else {
        showToast('Nenhuma alteração detectada.', 'info');
    }
}

// ============================================
// EXPORT FUNCTIONALITY
// ============================================
function exportToCSV() {
    const data = SHEET_DATA[currentSheet];
    if (!data || data.length === 0) return;

    let csv = '';
    data.forEach(row => {
        const cells = row.map(cell => {
            const val = (cell || '').toString().replace(/"/g, '""');
            return val.includes(',') || val.includes('\n') || val.includes('"') ? `"${val}"` : val;
        });
        csv += cells.join(';') + '\n';
    });

    const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `${currentSheet}.csv`;
    link.click();
    showToast('Arquivo CSV exportado com sucesso!', 'success');
}

// ============================================
// COPY TO CLIPBOARD
// ============================================
async function copyCellContent(value, button) {
    const text = (value || '').toString().trim();
    if (!text) return;

    try {
        if (navigator.clipboard && window.isSecureContext) {
            await navigator.clipboard.writeText(text);
        } else {
            fallbackCopyText(text);
        }

        showCopyFeedback(button);
        showToast('Conteúdo copiado.', 'success');
    } catch (error) {
        console.error('Copy failed:', error);
        showToast('Não foi possível copiar o conteúdo.', 'error');
    }
}

function fallbackCopyText(text) {
    const textarea = document.createElement('textarea');
    textarea.value = text;
    textarea.setAttribute('readonly', '');
    textarea.style.position = 'fixed';
    textarea.style.top = '-1000px';
    textarea.style.left = '-1000px';
    document.body.appendChild(textarea);
    textarea.select();
    document.execCommand('copy');
    textarea.remove();
}

function showCopyFeedback(button) {
    button.classList.add('copied');
    button.innerHTML = CHECK_ICON;
    button.title = 'Copiado!';
    button.setAttribute('aria-label', 'Conteúdo copiado');

    setTimeout(() => {
        button.classList.remove('copied');
        button.innerHTML = COPY_ICON;
        button.title = 'Copiar conteúdo';
        button.setAttribute('aria-label', 'Copiar conteúdo');
    }, 1600);
}

// ============================================
// TOAST NOTIFICATIONS
// ============================================
function showToast(message, type = 'info') {
    const container = document.getElementById('toastContainer');
    const toast = document.createElement('div');
    toast.className = `toast toast-${type}`;
    toast.textContent = message;
    container.appendChild(toast);

    setTimeout(() => toast.remove(), 3000);
}

// Close modal on overlay click
document.getElementById('loginModal').addEventListener('click', (e) => {
    if (e.target === document.getElementById('loginModal')) closeLogin();
});
